    # Try tuple/list like (a, b) or [a, b]
    if (s.startswith("(") and s.endswith(")")) or (s.startswith("[") and s.endswith("]")) or (s.startswith("{") and s.endswith("}")):
        inner = s[1:-1].strip()
        parts = [p.strip() for p in inner.split(",")]
        if len(parts) == 2:
            try:
                a = int(parts[0])
                b = int(parts[1])
                return (a, b)
            except Exception:
                pass
    # Try "a,b"
    if "," in s:
        parts = [p.strip() for p in s.split(",")]
        if len(parts) == 2:
            try:
                a = int(parts[0])
                b = int(parts[1])
                return (a, b)
            except Exception:
                pass
    # Try "[-13,3]" with possible spaces
    # Try two-int strings
    try:
        a = int(s)
        return (a, a)
    except Exception:
        pass
    return None

