    # parse candidate answer defensively
    s = str(answer).strip()
    # Try interpreting common forms: fraction like "1/15", decimal, or numeric types
    cand_frac = None
    try:
        # If it's already a Fraction or int/float, handle directly
        if isinstance(answer, Fraction):
            cand_frac = answer
        elif isinstance(answer, float):
            # compare as float
            return abs(float(answer) - float(expected_frac)) < 1e-9
        else:
            # try parse as integer
