            elif isinstance(parsed, (list, tuple)):
                vec = list(parsed)
            else:
                # If it's a single expression, fail
                return False
        if len(vec) != 3:
            return False
        # convert entries to sympy objects
        v = Matrix([sympify(vec[0]), sympify(vec[1]), sympify(vec[2])])
    except Exception:
        return False

    # define a
