def verify(answer):
    x = symbols('x')
    # define expression
    expr = ( (x+1)*(x-3) ) / (5*(x+2)*(x-4)) + ( (x+3)*(x-5) ) / (9*(x+4)*(x-6)) - ( 2*(x+5)*(x-7) ) / (13*(x+6)*(x-8)) - Rational(92,585)
    # get common denominator and numerator by writing as single rational and taking numerator
    expr_s = simplify(expr)
    num = Poly(expr_s.as_numer_denom()[0], x)
    den = Poly(expr_s.as_numer_denom()[1], x)
    # compute numeric roots of numerator
    roots = nroots(num)
    # filter real roots (imag ~ 0) and exclude poles where denominator is zero
    poles = [-2, 4, -4, 6, -6, 8]
    real_roots = []
    for r in roots:
        if abs(float(r.as_real_imag()[1])) < 1e-8:
            rv = float(r.as_real_imag()[0])
            if not any(abs(rv - p) < 1e-8 for p in poles):
                real_roots.append(rv)
    # unique within tol
    def uniq_sorted(lst, tol=1e-7):
        out = []
        for v in sorted(lst):
            if not out or abs(v - out[-1]) > tol:
                out.append(v)
        return out
    real_roots = uniq_sorted(real_roots)
    # parse answer: expect comma separated numbers
    try:
        s = str(answer).strip()
        if s == "":
            return False
        parts = [p.strip() for p in s.split(',')]
        cand = []
        for p in parts:
            # allow rational like "3/2"
            if '/' in p:
                num, denp = p.split('/')
                cand.append(float(int(num.strip())/int(denp.strip())))
            else:
                cand.append(float(p))
        cand = uniq_sorted(cand)
    except Exception:
        return False
    if len(cand) != len(real_roots):
        return False
    # compare each within tolerance
    tol = 1e-6
    for a, b in zip(cand, real_roots):
        if abs(a - b) > tol:
            return False
    return True

