def _to_binary_fraction(frac, max_bits=100):
    # frac is Fraction between 0 and 1
    bits = []
    r = frac
    for _ in range(max_bits):
        if r == 0:
            break
        r *= 2
        if r >= 1:
            bits.append('1')
            r -= 1
        else:
            bits.append('0')
    if r != 0:
        return None  # would be repeating beyond max_bits
    return ''.join(bits) if bits else '0'

