        return False
    expected_bits = _to_binary_fraction(frac_part, max_bits=100)
    if expected_bits is None:
        return False
    expected_forms = set()
    # canonical forms: "0.xxx", ".xxx"
    expected_forms.add('0.' + expected_bits)
    expected_forms.add('.' + expected_bits)
    # also allow explicit base suffix like "_2" or "₂" or " (base 2)"
    expected_forms.update(s + '_2' for s in list(expected_forms))
