def _f(x):
    # define radicands
    r1 = 3*x*x - 8*x + 1
    r2 = 9*x*x - 24*x - 8
    if r1 < 0 or r2 < 0:
        return None
    return math.sqrt(r1) + math.sqrt(r2) - 3

def _find_roots(xmin=-100, xmax=100, step=0.001, tol=1e-10):
    roots = []
    x = xmin
    prev_x = x
    prev_f = _f(prev_x)
    # advance initial to first defined f
    while prev_f is None and prev_x < xmax:
        prev_x += step
        prev_f = _f(prev_x)
    x = prev_x + step
    while x <= xmax:
        fx = _f(x)
        if fx is None:
            prev_x = x
            prev_f = fx
            x += step
            continue
        # check near-zero
        if abs(fx) < 1e-9:
            # refine by bisection around small neighborhood
            a = x - step
            b = x + step
            # ensure a,b defined
            if _f(a) is None:
                a = x
            if _f(b) is None:
                b = x
            lo, hi = a, b
            for _ in range(50):
                mid = (lo+hi)/2
                fm = _f(mid)
                if fm is None:
                    lo = mid
                    continue
                if abs(fm) < tol:
                    lo = mid - (hi-lo)/4
                    hi = mid + (hi-lo)/4
                else:
                    # try to bracket by sign with lo
                    if _f(lo) is not None and _f(lo)*fm <= 0:
                        hi = mid
                    else:
                        lo = mid
            root = (lo+hi)/2
            roots.append(root)
        if prev_f is not None and fx is not None and prev_f*fx < 0:
            a, b = prev_x, x
            fa, fb = prev_f, fx
            # bisection
            for _ in range(60):
                m = (a+b)/2
                fm = _f(m)
                if fm is None:
                    a = m
                    continue
                if fa*fm <= 0:
                    b = m
                    fb = fm
                else:
                    a = m
                    fa = fm
            roots.append((a+b)/2)
        prev_x = x
        prev_f = fx
        x += step
    # unique within 1e-7
    roots_sorted = []
    roots = sorted(roots)
    for r in roots:
        if all(abs(r - q) > 1e-6 for q in roots_sorted):
            roots_sorted.append(r)
    return roots_sorted

